queries.sparql:
PREFIX : <http://ambrosia.example.org/housingmarket#>
PREFIX p: <http://ambrosia.example.org/housingmarket/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?school_type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasschools ?child ; p:hassuburbs ?parent . } GROUP BY ?child }
  ?child p:school_type ?school_type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :suburbs } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/housingmarket#>
PREFIX p: <http://ambrosia.example.org/housingmarket/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?school_type WHERE {
  ?suburbs_schools a :suburbs_schools .
  ?schools a :schools .
  ?suburbs_schools p:hasschools ?schools .
  ?suburbs a :suburbs .
  ?suburbs_schools p:hassuburbs ?suburbs .
  ?suburbs p:name ?name .
  ?schools p:school_type ?school_type .
} }
  collective: { SELECT ?school_type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasschools ?child ; p:hassuburbs ?parent . } GROUP BY ?child }
  ?child p:school_type ?school_type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :suburbs } }
  FILTER(?nf = ?total)
} }
}
